import{_ as t,o,c as n,ae as a}from"./chunks/framework.DTQlDYOH.js";const u=JSON.parse('{"title":"Reference: Condition types","description":"","frontmatter":{},"headers":[],"relativePath":"reference/conditions.md","filePath":"reference/conditions.md"}'),s={name:"reference/conditions.md"};function r(i,e,l,g,c,d){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="reference-condition-types" tabindex="-1">Reference: Condition types <a class="header-anchor" href="#reference-condition-types" aria-label="Permalink to &quot;Reference: Condition types&quot;">​</a></h1><p>Conditions are used in move <strong>arguments</strong> (to restrict choices), in <strong>endIf</strong> (to detect win/draw), and in <strong>initialMoves</strong> / <strong>then</strong> (to decide when to run a move). Each condition object has a <strong>conditionType</strong> and type-specific fields.</p><h2 id="is" tabindex="-1">Is <a class="header-anchor" href="#is" aria-label="Permalink to &quot;Is&quot;">​</a></h2><p>Match an entity (or the current <strong>target</strong>) against a <strong>matcher</strong>. Uses lodash-style matching on entity rule + state.</p><ul><li><strong>matcher</strong> — Object with <code>name</code>, <code>type</code>, <code>player</code>, or state fields. <strong>player</strong> can be a resolved value (e.g. <strong>ctxPath</strong> <code>[&quot;currentPlayer&quot;]</code>).</li><li><strong>entity</strong> — Optional. When present, the condition is checked against this entity instead of <strong>target</strong>.</li></ul><h2 id="not-or" tabindex="-1">Not / Or <a class="header-anchor" href="#not-or" aria-label="Permalink to &quot;Not / Or&quot;">​</a></h2><ul><li><strong>Not</strong> — <strong>conditions</strong>: array of one or more conditions; passes when all fail.</li><li><strong>Or</strong> — <strong>conditions</strong>: array; passes when at least one passes.</li></ul><h2 id="contains" tabindex="-1">Contains <a class="header-anchor" href="#contains" aria-label="Permalink to &quot;Contains&quot;">​</a></h2><p>The <strong>target</strong> (a space or container) contains something matching nested <strong>conditions</strong>. If no nested conditions, “contains anything”. Often used as <strong>Not</strong> + <strong>Contains</strong> for “empty”.</p><h2 id="containssame" tabindex="-1">ContainsSame <a class="header-anchor" href="#containssame" aria-label="Permalink to &quot;ContainsSame&quot;">​</a></h2><p>Used inside a <strong>sequence</strong> (see InLine / HasLine). All items in the segment share the same value for the given <strong>properties</strong> (e.g. <code>[&quot;player&quot;]</code> for “same owner”).</p><h2 id="some-every" tabindex="-1">Some / Every <a class="header-anchor" href="#some-every" aria-label="Permalink to &quot;Some / Every&quot;">​</a></h2><p>Quantifiers over a set.</p><ul><li><strong>target</strong> — Resolution that yields multiple entities (e.g. <strong>matchMultiple</strong> + <strong>conditions</strong> for “all spaces in grid”).</li><li><strong>conditions</strong> — Conditions that must hold for <strong>Some</strong> (at least one) or <strong>Every</strong> (all).</li></ul><p>Used in: Connect Four (some space has a line of 4; every space filled → draw).</p><h2 id="inline" tabindex="-1">InLine <a class="header-anchor" href="#inline" aria-label="Permalink to &quot;InLine&quot;">​</a></h2><p>The current <strong>target</strong> (usually a space) lies in a line (row/column/diagonal) that matches a <strong>sequence</strong>.</p><ul><li><strong>target</strong> — Optional. Defaults to the context target (e.g. the chosen destination).</li><li><strong>sequence</strong> — Array of segment rules: <strong>minCount</strong> (or <strong>maxCount</strong>) and <strong>conditions</strong> that each segment must satisfy. Used for “in a line of N with same player” (Reversi, Connect Four).</li></ul><h2 id="hasline" tabindex="-1">HasLine <a class="header-anchor" href="#hasline" aria-label="Permalink to &quot;HasLine&quot;">​</a></h2><p>The grid (or <strong>target</strong>) has at least one line matching the <strong>sequence</strong>. Same <strong>sequence</strong> shape as InLine.</p><ul><li><strong>target</strong> — Entity name (string) or conditions for the grid.</li><li><strong>sequence</strong> - e.g. one segment with minCount 3 and conditions ContainsSame on properties [&quot;player&quot;] for three in a row.</li></ul><p>Used in: tic-tac-toe, Connect Four.</p><h2 id="isfull" tabindex="-1">IsFull <a class="header-anchor" href="#isfull" aria-label="Permalink to &quot;IsFull&quot;">​</a></h2><p><strong>target</strong> (grid or container) has no empty spaces. Used for draw when the board is full.</p><h2 id="would" tabindex="-1">Would <a class="header-anchor" href="#would" aria-label="Permalink to &quot;Would&quot;">​</a></h2><p>“Would this move be valid?” Used by the UI to highlight legal moves. Takes the same shape as the move’s argument conditions.</p><h2 id="nopossiblemoves" tabindex="-1">NoPossibleMoves <a class="header-anchor" href="#nopossiblemoves" aria-label="Permalink to &quot;NoPossibleMoves&quot;">​</a></h2><p>True when there are no legal moves for the current move name (or current context). Used in <strong>initialMoves</strong> to allow <strong>PassTurn</strong> or to advance to another stage (e.g. “if no jump, go to move stage”).</p><h2 id="evaluate" tabindex="-1">Evaluate <a class="header-anchor" href="#evaluate" aria-label="Permalink to &quot;Evaluate&quot;">​</a></h2><p>Boolean expression evaluated with <a href="https://github.com/silentmatt/expr-eval" target="_blank" rel="noreferrer">expr-eval</a>.</p><ul><li><strong>expression</strong> — String (e.g. <code>&quot;player == &#39;0&#39;&quot;</code>, <code>&quot;passCount &gt; 0&quot;</code>).</li><li><strong>arguments</strong> — Object mapping variable names to resolved values (e.g. <strong>ctxPath</strong>, <strong>gamePath</strong>). Available inside <strong>expression</strong>.</li></ul><p>Used in: Checkers (king row check, pass count for win).</p><h2 id="position" tabindex="-1">Position <a class="header-anchor" href="#position" aria-label="Permalink to &quot;Position&quot;">​</a></h2><p>Position-based condition (e.g. coordinates). See engine source for current parameters.</p><hr><p><strong>target</strong> — Many conditions accept an optional <strong>target</strong>. It can be a string (entity name), or an object with <strong>type</strong> and <strong>path</strong> (e.g. <strong>contextPath</strong>, <strong>gamePath</strong>) resolving to a space or entity. If omitted, the condition uses the current context <strong>target</strong> (e.g. the space being validated as a move destination).</p>',36)])])}const p=t(s,[["render",r]]);export{u as __pageData,p as default};
